arguments.command:
python3 - << 'PY'
import os,json
from glob import glob
p='docs-site/docs'
pages=[]
for f in glob(p+'/*.md'):
    with open(f,'r',encoding='utf-8') as fh:
        txt=fh.read()
    fm={}
    title=None
    if txt.startswith('---'):
        parts=txt.split('---',2)
        if len(parts)>2:
            block=parts[1]
            for line in block.splitlines():
                if ':' in line:
                    k,v=line.split(':',1)
                    fm[k.strip()]=v.strip().strip('"')
    if 'title' in fm:
        title=fm['title']
    else:
        for line in txt.splitlines():
            if line.strip().startswith('# '):
                title=line.strip()[2:]
                break
    pages.append({
        'path': os.path.basename(f),
        'title': title,
        'audience': fm.get('audience'),
        'tags': [t.strip() for t in fm.get('tags','[]').strip('[]').split(',') if t.strip()],
        'summary': fm.get('summary')
    })
print(json.dumps({'generated_at':None,'pages':pages},indent=2))
PY

